const body = $input.first().json.body || $input.first().json;

const topic = (body.topic || 'AI automation trends').trim().toLowerCase();
const audience = (body.audience || 'general').trim().toLowerCase();
const priority = (body.priority || 'normal').trim().toLowerCase();

const topicId = topic.replace(/\s+/g, '_') + '_' + Date.now();
const runId = 'run_' + Math.random().toString(36).substring(2, 10);
const timestamp = new Date().toISOString();

return [{
  json: {
    topic,
    audience,
    priority,
    topicId,
    runId,
    timestamp,
    normalizedInput: { topic, audience, priority }
  }
}];

