const raw = $input.first().json;

let parsedItems = [];
try {
  const content = raw.content?.[0]?.text || raw.choices?.[0]?.message?.content || '';
  parsedItems = JSON.parse(content);
} catch (e) {
  parsedItems = [];
}

if (!Array.isArray(parsedItems)) parsedItems = [];

const filtered = parsedItems.filter(item =>
  item.confidence_score >= 0.6 &&
  item.title &&
  item.summary
);

const inputData = $('Input Processing').item.json;

return filtered.map(item => ({
  json: {
    ...item,
    topic: inputData.topic,
    audience: inputData.audience,
    priority: inputData.priority,
    topicId: inputData.topicId,
    runId: inputData.runId,
    timestamp: inputData.timestamp
  }
}));

