const raw = $input.first().json;

let decision = {};
try {
  const content = raw.content?.[0]?.text || '';
  decision = JSON.parse(content);
} catch (e) {
  decision = {
    decision: 'ignore',
    reason: 'Failed to parse AI decision response',
    email_subject: '',
    email_body_html: '',
    insights: [],
    sources: []
  };
}

const inputData = $('Input Processing').item.json;

return [{
  json: {
    ...decision,
    topic: inputData.topic,
    audience: inputData.audience,
    priority: inputData.priority,
    topicId: inputData.topicId,
    runId: inputData.runId,
    timestamp: inputData.timestamp
  }
}];

const input = $('Input Processing').item.json;
const decision = $('Parse Decision Output').item?.json || {};
const emailSent = $('Send Email').item?.json || null;

const logEntry = {
  runId: input.runId,
  topicId: input.topicId,
  topic: input.topic,
  audience: input.audience,
  priority: input.priority,
  timestamp: input.timestamp,
  completedAt: new Date().toISOString(),
  decision: decision.decision || 'unknown',
  decisionReason: decision.reason || '',
  emailSent: !!emailSent,
  insightsCount: (decision.insights || []).length,
  sourcesCount: (decision.sources || []).length,
  status: 'success'
};

console.log('[EXECUTION LOG]', JSON.stringify(logEntry, null, 2));

return [{ json: logEntry }];

